mapper.select:
SELECT ds.id, ds.clinic_id AS clinicId, c.clinic_name AS clinicName, ds.doctor_id AS doctorId, s.staff_name AS doctorName, ds.room_id AS roomId, r.room_name AS roomName, ds.schedule_date AS scheduleDate, ds.start_time AS startTime, ds.end_time AS endTime, ds.schedule_type AS scheduleType, ds.max_appointment_count AS maxAppointmentCount, ds.status, ds.remark FROM doctor_schedule ds LEFT JOIN clinic c ON c.id = ds.clinic_id LEFT JOIN staff s ON s.id = ds.doctor_id LEFT JOIN room r ON r.id = ds.room_id WHERE ds.org_id = #{orgId} AND ds.is_deleted = 0
AND ds.clinic_id IN
#{clinicId}
AND 1 = 0
AND ds.doctor_id = #{staffId}
AND 1 = 0
AND ds.schedule_date = #{query.scheduleDate}
AND ds.clinic_id = #{query.clinicId}
AND ds.doctor_id = #{query.doctorId}
AND ds.status = #{query.status}
ORDER BY ds.schedule_date DESC, ds.start_time ASC, ds.id ASC
